        <tr><td colspan="${t.length}" style="padding:6px 10px;border:1px solid #E5E7EB;font-size:11px;">Aguas: 38,75 h &nbsp;·&nbsp; Alumbrado: 40,00 h &nbsp;·&nbsp; Jardines: 37,50 h &nbsp;·&nbsp; Limpieza de edificios: 39,00 h &nbsp;·&nbsp; Limpiezas Publicas: 37,50 h &nbsp;·&nbsp; Piscinas: 40,00 h &nbsp;·&nbsp; Instalaciones Deportivas: 40,00 h</td></tr>
